    "cases.set_up_bim_requirements_and_coordination.step.coordinate.out.federation": "Federacja modeli",
    "cases.set_up_bim_requirements_and_coordination.step.coordinate.title": "Ustal rytm koordynacji",
    "cases.set_up_bim_requirements_and_coordination.step.coordinate.what": "Ustal federację i regularny cykl koordynacji względem tych wymagań: kto co wydaje, kiedy modele się łączą i jak często zespół spotyka się, by rozwiązywać kolizje.",
    "cases.set_up_bim_requirements_and_coordination.step.coordinate.why": "Koordynacja, która odbywa się wtedy, gdy ktoś sobie o niej przypomni, odbywa się za późno. Stały rytm powiązany z wymaganiami utrzymuje branże w zgraniu zamiast zderzenia na budowie.",
    "cases.set_up_bim_requirements_and_coordination.step.requirements.in.brief": "Wymagania inwestora",
    "cases.set_up_bim_requirements_and_coordination.step.requirements.in.standards": "Obowiązujące standardy",
    "cases.set_up_bim_requirements_and_coordination.step.requirements.out.matrix": "Matryca wymagań",
