    "costs.load_failed_unreachable": "Nie udało się połączyć z serwerem danych, aby pobrać ten region. Często przyczyną jest zablokowana sieć lub problem z połączeniem z GitHub. Sprawdź swoje połączenie oraz dostępność github.com, a następnie spróbuj ponownie.",
    "costs.load_failed_retry": "Ponów",
    "setup.load_failed_title": "Nie udało się załadować {{name}}",
    "setup.load_failed_unreachable": "Nie udało się połączyć z serwerem danych, aby pobrać ten region. Często przyczyną jest zablokowana sieć lub problem z połączeniem z GitHub. Sprawdź swoje połączenie oraz dostępność github.com, a następnie spróbuj ponownie.",
    "setup.load_failed_retry": "Ponów",
    "setup.catalog_partial_title": "Załadowano stawki, zasoby niedostępne",
    "setup.catalog_partial_message": "Stawki zostały załadowane. Rozbicie na zasoby jest obecnie niedostępne dla tego regionu, często z powodu zablokowanej sieci lub problemu z połączeniem z GitHub. Stawki działają i bez tego, możesz ponowić próbę pobrania zasobów.",
    "boq.copilot.apply_failed": "Nie udało się zastosować tej zmiany.",
    "whatsnew.v820.journey.title": "Mapa ścieżki projektu na górnym pasku",
    "whatsnew.v820.journey.chip": "Mapa ścieżki",
    "whatsnew.v820.journey.b1": "Element na górnym pasku wskazuje fazę cyklu życia, do której należy ekran, na którym się znajdujesz.",
    "whatsnew.v820.journey.b2": "Otwórz ją, aby zobaczyć cały projekt od pierwszego leada po przekazanie: trzy łuki i jedenaście numerowanych faz.",
    "whatsnew.v820.journey.b3": "Każdy główny moduł znajduje się w swojej fazie jako odnośnik i jest przetłumaczony na każdy język.",
    "whatsnew.v820.fx.title": "Zabezpieczenie przed odwróconym kursem waluty",
    "whatsnew.v820.fx.chip": "Zabezpieczenie FX",
    "whatsnew.v820.fx.b1": "Okno waluty ostrzega, gdy kurs wymiany projektu wygląda na wprowadzony odwrotnie.",
    "whatsnew.v820.fx.b2": "Sygnalizuje też kurs znacznie odbiegający od typowego kursu rynkowego i pokazuje go we właściwej kolejności.",
    "whatsnew.v820.fx.b3": "Pomyłka nie zniekształca już po cichu zsumowanych wartości.",
    "whatsnew.v820.bim.title": "Walidacja importu zbiorczego BIM",
    "whatsnew.v820.bim.chip": "Import BIM",
    "whatsnew.v820.bim.b1": "Modele importowane z arkusza kalkulacyjnego lub pliku zbiorczego elementów przechodzą teraz tę samą walidację co ścieżka CAD.",
    "whatsnew.v820.bim.b2": "Każdy importowany model otrzymuje raport walidacji, nie tylko te wprowadzone przez konwerter.",
    "whatsnew.v820.takeoff.title": "Przedmiar oznacza strony zeskanowane",
    "whatsnew.v820.takeoff.chip": "Strony zeskanowane",
    "whatsnew.v820.takeoff.b1": "Przedmiar robót zgłasza teraz, ile stron PDF nie zawiera warstwy tekstowej, zwykle są to zeskanowane rysunki.",
    "whatsnew.v820.takeoff.b2": "Nie są już po cichu traktowane jako puste, więc wiadomo, które strony wymagają OCR.",
    "whatsnew.v820.din276.title": "Kropkowane kody CAD wg DIN 276",
    "whatsnew.v820.din276.chip": "DIN 276",
    "whatsnew.v820.din276.b1": "Kontrole kompletności i hierarchii sprowadzają teraz kropkowane kody CAD, takie jak 330.10, do ich trzycyfrowej grupy kosztów.",
    "whatsnew.v820.din276.b2": "Model sklasyfikowany za pomocą bardziej szczegółowych kodów jest oceniany względem właściwej grupy, zamiast być zaniżany.",
    "whatsnew.v820.fixes.title": "Poprawki komentarzy i podglądu DWG",
    "whatsnew.v820.fixes.chip": "Poprawki",
    "whatsnew.v820.fixes.b1": "Komentarz zawierający punkt widzenia sprawdza teraz typ swojej encji względem tej samej listy dozwolonych co ścieżka samodzielna.",
    "whatsnew.v820.fixes.b2": "Podglądy rysunków DWG ponownie renderują się w nowszych wersjach ezdxf, od wersji 1.1 wzwyż.",
    "takeoff.needs_ocr_banner": "{{n}} z {{total}} stron nie ma warstwy tekstowej i prawdopodobnie wymaga OCR.",
