    "changeorders.execute_confirm": "Oznaczyć to zlecenie zmiany jako wykonane? Rejestruje to, że zmiana zakresu została zrealizowana na budowie. Nie można tego cofnąć.",
    "changeorders.execute_confirm_title": "Oznaczyć jako wykonane?",
    "changeorders.executed": "Zlecenie zmiany oznaczone jako wykonane",
    "changeorders.impact_days_suffix": "d",
    "changeorders.impact_saved_scenarios": "Zapisane scenariusze",
